#!/bin/bash


echo "import Foundation


struct File: Codable {
    let filename: String
    let content: String
}


struct Script: Codable {
    let name: String
    let content: String
}


typealias Template = [String: [File], String: [Script]]


func createFilesAndRunScripts(outputPath: String, from jsonString: String) {
    let fileManager = FileManager.default

    if !fileManager.fileExists(atPath: outputPath) {
        do {
            try fileManager.createDirectory(atPath: outputPath, withIntermediateDirectories: true, attributes: nil)
        } catch {
            print(\"Error: Could not create output directory.\")
            return
        }
    }

    guard let jsonData = jsonString.data(using: .utf8) else {
        print(\"Error: Invalid JSON string.\")
        return;
    }
    let decoder = JSONDecoder();
    let template: Template;


    do {
        template = try decoder.decode(Template.self, from: jsonData);
    } catch {
        print(\"Error: Invalid JSON string.\")
        return;
    }

    for file in template[\"file\"]! {
        do {
            let fileURL = URL(fileURLWithPath: outputPath).appendingPathComponent(file.filename)
            try file.content.write(to: fileURL, atomically: true, encoding: .utf8);
            print(\"Created file: \(file.filename)\");
        } catch {
            print(\"Error: Could not create file \(file.filename)\");
        }
    }

    for script in template[\"script\"]! {
        do {
            print(\"Executing script: \\(script.name)\")
            let task = Process()
            task.currentDirectoryURL = URL(fileURLWithPath: outputPath).absoluteURL
            task.executableURL = URL(fileURLWithPath: script.content).absoluteURL
            task.launchPath = task.executableURL?.absoluteURL.path
            task.arguments = []
            let pipe = Pipe()
            task.standardOutput = pipe
            try task.run()
            task.waitUntilExit()
            let data = pipe.fileHandleForReading.readDataToEndOfFile()
            let output = String(data: data, encoding: .utf8)
            print(\"Output of \\(script.name): \n\(output ?? \"No output\").\")
        } catch (let error) {
            print(\"Error: Could not execute script \\(script.name)\", error)
        }
    }
}


if CommandLine.arguments.count != 3 {
    print(\"Usage: ./Project outputDirectoryPath pathToFile\")
    exit(1)
}


let outputPath = CommandLine.arguments[1]
let pathToFile = CommandLine.arguments[2]
if let jsonString = try? String(contentsOfFile: pathToFile) {
    createFilesAndRunScripts(outputPath: outputPath, from: jsonString)
} else {
    print(\"Error: Could not read JSON file at path '\(pathToFile)'\")
}
" > ./Project/Sources/Project/main.swift
